 14→ * Lints and formats the spacing after the fun keyword
 15→ */
 16→public class FunctionStartOfBodySpacingRule : StandardRule("function-start-of-body-spacing") {
 17→    override fun beforeVisitChildNodes(
 18→        node: ASTNode,
 19→        autoCorrect: Boolean,
 20→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 21→    ) {
 22→        if (node.elementType == FUN) {
 23→            node
 24→                .findChildByType(ElementType.EQ)
 25→                ?.let { visitFunctionFollowedByBodyExpression(node, emit, autoCorrect) }
 26→
 27→            node
 28→                .findChildByType(ElementType.BLOCK)
 29→                ?.let { visitFunctionFollowedByBodyBlock(node, emit, autoCorrect) }
 30→        }
 31→    }
 32→
 33→    private fun visitFunctionFollowedByBodyExpression(
 34→        node: ASTNode,
 35→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 36→        autoCorrect: Boolean,
 37→    ) {
 38→        fixWhiteSpaceBeforeAssignmentOfBodyExpression(node, emit, autoCorrect)
 39→        fixWhiteSpaceBetweenAssignmentAndBodyExpression(node, emit, autoCorrect)
 40→    }
 41→
 42→    private fun fixWhiteSpaceBeforeAssignmentOfBodyExpression(
 43→        node: ASTNode,
 44→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 45→        autoCorrect: Boolean,
 46→    ) {
 47→        node
 48→            .findChildByType(ElementType.EQ)
 49→            ?.let { assignmentExpression ->
 50→                assignmentExpression
 51→                    .prevLeaf(includeEmpty = true)
 52→                    ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 53→                    .let { whiteSpaceBeforeAssignment ->
 54→                        if (whiteSpaceBeforeAssignment == null) {
 55→                            emit(
 56→                                assignmentExpression.startOffset,
 57→                                "Expected a single white space before assignment of expression body",
 58→                                true,
 59→                            )
 60→                            if (autoCorrect) {
 61→                                assignmentExpression.upsertWhitespaceBeforeMe(" ")
 62→                            }
 63→                        } else if (whiteSpaceBeforeAssignment.text != " ") {
 64→                            emit(whiteSpaceBeforeAssignment.startOffset, "Unexpected whitespace", true)
 65→                            if (autoCorrect) {
 66→                                assignmentExpression.upsertWhitespaceBeforeMe(" ")
 67→                            }
 68→                        }
 69→                    }
 70→            }
 71→    }
 72→
 73→    private fun fixWhiteSpaceBetweenAssignmentAndBodyExpression(
 74→        node: ASTNode,
 75→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 76→        autoCorrect: Boolean,
 77→    ) {
 78→        node
 79→            .findChildByType(ElementType.EQ)
 80→            ?.let { assignmentExpression ->
 81→                assignmentExpression
 82→                    .nextLeaf(includeEmpty = true)
 83→                    ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 84→                    .let { whiteSpaceAfterAssignment ->
 85→                        if (!(whiteSpaceAfterAssignment?.text == " " || whiteSpaceAfterAssignment?.textContains('\n') == true)) {
 86→                            emit(
 87→                                assignmentExpression.startOffset,
 88→                                "Expected a single white space between assignment and expression body on same line",
 89→                                true,
 90→                            )
 91→                            if (autoCorrect) {
 92→                                assignmentExpression.upsertWhitespaceAfterMe(" ")
 93→                            }
 94→                        }
 95→                    }
 96→            }
 97→    }
 98→
 99→    private fun visitFunctionFollowedByBodyBlock(
100→        node: ASTNode,
101→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
102→        autoCorrect: Boolean,
103→    ) {
104→        node
105→            .findChildByType(ElementType.BLOCK)
106→            ?.let { block ->
107→                block
108→                    .prevLeaf(includeEmpty = true)
109→                    ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
110→                    .let { whiteSpaceBeforeExpressionBlock ->
111→                        if (whiteSpaceBeforeExpressionBlock?.text != " ") {
112→                            emit(block.startOffset, "Expected a single white space before start of function body", true)
113→                            if (autoCorrect) {
114→                                block
115→                                    .firstChildNode
116→                                    .prevLeaf(true)
117→                                    ?.upsertWhitespaceAfterMe(" ")
118→                            }
119→                        }
120→                    }
121→            }
122→    }
