        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ): Int {
        val actualFunctionSignatureLength = node.getFunctionSignatureLength()

        // Calculate the length of the function signature in case it would be rewritten as single line (and without a
        // maximum line length). The white space correction will be calculated via a dry run of the actual fix.
        val parameterListWhitespaceCorrection =
            fixWhiteSpacesInValueParameterList(node, emit, autoCorrect, multiline = false, dryRun = true)

        // Also account for the space needed before the body block/expression
        val bodySpacingCorrection = calculateBodySpacingCorrection(node)

        return actualFunctionSignatureLength + parameterListWhitespaceCorrection + bodySpacingCorrection
    }

    private fun calculateBodySpacingCorrection(node: ASTNode): Int {
        // Check if there's a body block
        val block = node.findChildByType(BLOCK)
        if (block != null) {
            val lastNodeOfFunctionSignatureWithBlockBody =
                node
                    .getLastNodeOfFunctionSignatureWithBlockBody()
                    ?.nextLeaf(includeEmpty = true)
                    ?: return 0

            val bodyNodes = node.getFunctionBody(lastNodeOfFunctionSignatureWithBlockBody)
            val whiteSpaceBeforeFunctionBodyBlock = bodyNodes.getStartingWhitespaceOrNull()

            // If there's no space or the space is not a single space, we need to add 1 char
            if (whiteSpaceBeforeFunctionBodyBlock?.text != " ") {
                return 1 - (whiteSpaceBeforeFunctionBodyBlock?.textLength ?: 0)
            }
        }
        return 0
    }"}

